using System;
using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Botão de uma faixa do Jukebox.
///
/// <b>Layout esperado no prefab:</b>
/// <code>
/// [Root] ─ JukeboxTrackButtonUI + LayoutGroup (Horizontal)
///   ├── DiscRoot (GameObject)            ← activado só na faixa a tocar
///   │     └── DiscTransform (Transform)  ← roda enquanto a faixa toca
///   ├── NameText (TMP_Text)              ← nome da faixa
///   ├── PlayStopButton (Button)          ← ▶ / ⏹ (muda sprite)
///   │     └── PlayStopIcon (Image)       ← sprite ▶ ou ⏹
///   └── FavoriteButton (Button)          ← ♥ / vazio
///         └── FavoriteIcon (Image)       ← sprite cheio/vazio
/// </code>
///
/// <b>Navegação:</b> configurar no Inspector (Explicit) para que
/// D-pad Direito passe de NameButton para FavoriteButton.
/// O botão PlayStop e o botão raiz do Row podem apontar para o mesmo evento —
/// ambos chamam <see cref="Clicked"/>.
/// </summary>
public class JukeboxTrackButtonUI : MonoBehaviour
{
    // ── Inspector ────────────────────────────────────────────────────────────

    [Header("Disco Giratório (à esquerda — só na faixa activa)")]
    [Tooltip("Raiz do disco — activada/desactivada conforme IsPlaying.")]
    [SerializeField] private GameObject discRoot;

    [Tooltip("Transform que roda enquanto a faixa está a tocar (ex: a imagem do disco/pata).")]
    [SerializeField] private Transform discTransform;

    [Tooltip("Velocidade de rotação do disco em graus/segundo (sentido anti-horário).")]
    [SerializeField] private float discRotationSpeed = 90f;

    [Header("Nome")]
    [SerializeField] private TMP_Text nameText;

    [Header("Botão Play / Stop (à direita)")]
    [SerializeField] private Button playStopButton;
    [SerializeField] private Image playStopIcon;
    [Tooltip("Sprite mostrado quando a faixa NÃO está a tocar (▶).")]
    [SerializeField] private Sprite playSprite;
    [Tooltip("Sprite mostrado quando a faixa ESTÁ a tocar (⏹).")]
    [SerializeField] private Sprite stopSprite;

    [Header("Botão Favorito (à direita do play)")]
    [SerializeField] private Button favoriteButton;
    [SerializeField] private Image favoriteIcon;
    [Tooltip("Sprite do favorito activo (♥ cheio).")]
    [SerializeField] private Sprite favoriteActiveSprite;
    [Tooltip("Sprite do favorito inactivo (♥ vazio / contorno).")]
    [SerializeField] private Sprite favoriteInactiveSprite;

    // ── Eventos ──────────────────────────────────────────────────────────────

    /// <summary>Disparado quando o botão de play/stop (ou o próprio row) é clicado.</summary>
    public event Action<JukeboxTrackButtonUI> Clicked;

    /// <summary>Disparado quando o botão de favorito é clicado.</summary>
    public event Action<JukeboxTrackButtonUI> FavoriteClicked;

    // ── Estado ───────────────────────────────────────────────────────────────

    /// <summary>Índice desta faixa na lista de exibição do <see cref="JukeboxSectionUI"/>.</summary>
    public int Index { get; private set; }

    private bool _isPlaying;

    // ── Unity ────────────────────────────────────────────────────────────────

    private void Awake()
    {
        if (playStopButton != null)
            playStopButton.onClick.AddListener(() => Clicked?.Invoke(this));

        if (favoriteButton != null)
            favoriteButton.onClick.AddListener(() => FavoriteClicked?.Invoke(this));
    }

    private void Update()
    {
        if (discTransform != null && _isPlaying)
            discTransform.Rotate(0f, 0f, -discRotationSpeed * Time.deltaTime);
    }

    // ── API Pública ──────────────────────────────────────────────────────────

    /// <summary>Configura o botão com os dados da faixa.</summary>
    public void Setup(int index, string displayName, bool isPlaying, bool isFavorite)
    {
        Index = index;

        if (nameText != null)
            nameText.text = displayName;

        SetPlaying(isPlaying);
        SetFavorite(isFavorite);
    }

    /// <summary>Actualiza o visual de "a tocar" (disco, ícone play/stop).</summary>
    public void SetPlaying(bool isPlaying)
    {
        _isPlaying = isPlaying;

        if (discRoot != null)
            discRoot.SetActive(isPlaying);

        if (playStopIcon != null)
        {
            var sprite = isPlaying ? stopSprite : playSprite;
            if (sprite != null) playStopIcon.sprite = sprite;
        }
    }

    /// <summary>Actualiza o visual do botão de favorito.</summary>
    public void SetFavorite(bool isFavorite)
    {
        if (favoriteIcon != null)
        {
            var sprite = isFavorite ? favoriteActiveSprite : favoriteInactiveSprite;
            if (sprite != null) favoriteIcon.sprite = sprite;
        }
    }
}
